// src/components/SplashCursor.jsx
'use client';
import { useEffect, useRef } from 'react';

/**
 * Full-screen WebGL fluid splash that only ever renders two colors:
 * teal (#57B2B6) and white (#FFFFFF).
 */
export default function SplashCursor({
  SIM_RESOLUTION = 128,
  DYE_RESOLUTION = 1440,
  CAPTURE_RESOLUTION = 512,
  DENSITY_DISSIPATION = 3.5,
  VELOCITY_DISSIPATION = 2,
  PRESSURE = 0.1,
  PRESSURE_ITERATIONS = 20,
  CURL = 3,
  SPLAT_RADIUS = 0.2,
  SPLAT_FORCE = 6000,
  SHADING = true,
  COLOR_UPDATE_SPEED = 10,
  BACK_COLOR = { r: 0x57/255, g: 0xB2/255, b: 0xB6/255 },
  TRANSPARENT = false
}) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // --- Utility functions ---
    const scaleByPixelRatio = v => Math.floor(v * (window.devicePixelRatio || 1));
    const correctDX = d => (canvas.width/canvas.height < 1 ? d*(canvas.width/canvas.height) : d);
    const correctDY = d => (canvas.width/canvas.height > 1 ? d/(canvas.width/canvas.height) : d);

    // --- WebGL context ---
    const gl = canvas.getContext('webgl2', { alpha: true, depth: false, stencil: false, antialias: false, preserveDrawingBuffer: false })
             || canvas.getContext('webgl')
             || canvas.getContext('experimental-webgl');
    const supportLinearFiltering = !!(gl.getExtension('OES_texture_float_linear') || gl.getExtension('OES_texture_half_float_linear'));

    // --- Shader sources ---
    const baseVertexShaderSource = `
      precision highp float;
      attribute vec2 aPosition;
      varying vec2 vUv;
      uniform vec2 texelSize;
      void main() {
        vUv = aPosition * 0.5 + 0.5;
        gl_Position = vec4(aPosition, 0.0, 1.0);
      }
    `;

    // Display shader: quantize to teal or white
    const displayShaderSource = `
      precision highp float;
      varying vec2 vUv;
      uniform sampler2D uTexture;
      void main() {
        vec3 c = texture2D(uTexture, vUv).rgb;
        vec3 teal  = vec3(0.341176, 0.698039, 0.713725);
        vec3 white = vec3(1.0);
        float br = max(max(c.r, c.g), c.b);
        vec3 outCol = br > 0.5 ? white : teal;
        gl_FragColor = vec4(outCol, 1.0);
      }
    `;

    // Splat shader: take pointer.color uniform
    const splatShaderSource = `
      precision highp float;
      varying vec2 vUv;
      uniform sampler2D uTarget;
      uniform vec3 color;
      uniform vec2 point;
      uniform float radius;
      void main() {
        float d = distance(vUv, point);
        float m = exp(-d*d / radius);
        vec3 base = texture2D(uTarget, vUv).rgb;
        gl_FragColor = vec4(base + color * m, 1.0);
      }
    `;

    // Utility: compile shader, create program
    function compile(src, type) {
      const sh = gl.createShader(type);
      gl.shaderSource(sh, src);
      gl.compileShader(sh);
      if (!gl.getShaderParameter(sh, gl.COMPILE_STATUS)) console.error(gl.getShaderInfoLog(sh));
      return sh;
    }
    function createProgram(vsSrc, fsSrc) {
      const vs = compile(vsSrc, gl.VERTEX_SHADER);
      const fs = compile(fsSrc, gl.FRAGMENT_SHADER);
      const prog = gl.createProgram();
      gl.attachShader(prog, vs);
      gl.attachShader(prog, fs);
      gl.linkProgram(prog);
      if (!gl.getProgramParameter(prog, gl.LINK_STATUS)) console.error(gl.getProgramInfoLog(prog));
      return prog;
    }

    // --- Programs ---
    const displayProgram = createProgram(baseVertexShaderSource, displayShaderSource);
    const splatProgram   = createProgram(baseVertexShaderSource, splatShaderSource);

    // ... set up FBOs, buffers, simulation programs as before ...
    // Insert your advection, divergence, pressure, etc. programs here.

    // Pointer and color logic
    function Pointer() {
      this.color = Math.random()<0.5
        ? vec3(0.341176,0.698039,0.713725) // teal
        : vec3(1.0,1.0,1.0);                // white
      this.tex = [0,0]; this.prev=[0,0]; this.delta=[0,0]; this.down=false; this.moved=false;
    }
    const pointers=[new Pointer()];

    // Override simulation's display pass to use displayProgram
    function renderDisplay() {
      gl.useProgram(displayProgram);
      // bind dye texture to unit 0
      gl.uniform1i(gl.getUniformLocation(displayProgram,'uTexture'),0);
      // draw full-screen quad
      gl.drawArrays(gl.TRIANGLE_STRIP,0,4);
    }

    // Splat wrapper
    function splat(x,y,dx,dy,color) {
      gl.useProgram(splatProgram);
      gl.uniform2f(gl.getUniformLocation(splatProgram,'point'), x, y);
      gl.uniform1f(gl.getUniformLocation(splatProgram,'radius'), SPLAT_RADIUS);
      gl.uniform3f(gl.getUniformLocation(splatProgram,'color'), color.r, color.g, color.b);
      // bind velocity or dye as uTarget, then draw...
    }

    // Main loop
    function step() {
      // simulation steps: advection, divergence, pressure, gradient subtract
      // ...
      // final display:
      renderDisplay();
      requestAnimationFrame(step);
    }
    step();

  }, [
    SIM_RESOLUTION,DYE_RESOLUTION,CAPTURE_RESOLUTION,
    DENSITY_DISSIPATION,VELOCITY_DISSIPATION,
    PRESSURE,PRESSURE_ITERATIONS,CURL,
    SPLAT_RADIUS,SPLAT_FORCE,SHADING,
    COLOR_UPDATE_SPEED,BACK_COLOR,TRANSPARENT
  ]);

  return (
    <canvas
      ref={canvasRef}
      id="fluid"
      style={{ position:'fixed',top:0,left:0,width:'100vw',height:'100vh',pointerEvents:'none' }}
    />
  );
}
